    # Check for two same color cards
    for i in range(3):
        if arr[i] >= 2:
            new_arr = arr.copy()
            new_arr[i] -= 1
            sub_res = determine(new_arr, memo)
            for j in range(3):
                if sub_res[j]:
                    res[j] = True

