            if arr[i] >= 1 and arr[j] >= 1:
                k = 3 - i - j
                new_arr = arr.copy()
                new_arr[i] -= 1
                new_arr[j] -= 1
                new_arr[k] += 1
                sub_res = determine(new_arr, memo)
                for l in range(3):
                    if sub_res[l]:
                        res[l] = True

    memo[key] = res
    return res

